import * as React from 'react'

import {useCombobox} from '../../src'
import {colors} from '../utils'

export default function DropdownCombobox() {
  const [inputItems, setInputItems] = React.useState(colors)
  const {
    isOpen,
    getToggleButtonProps,
    getLabelProps,
    getMenuProps,
    getInputProps,
    highlightedIndex,
    getItemProps,
    selectedItem,
    selectItem,
  } = useCombobox({
    items: inputItems,
    onInputValueChange: ({inputValue}) => {
      setInputItems(
        colors.filter(item =>
          item.toLowerCase().startsWith(inputValue.toLowerCase()),
        ),
      )
    },
  })
  return (
    <div className="container">
      <label
        style={{
          fontWeight: 'bolder',
          color: selectedItem ? selectedItem : 'black',
        }}
        {...getLabelProps()}
      >
        Choose an element:
      </label>
      <div>
        <input
          style={{padding: '4px'}}
          {...getInputProps()}
          data-testid="combobox-input"
        />
        <button
          style={{padding: '4px 8px'}}
          aria-label="toggle menu"
          data-testid="combobox-toggle-button"
          {...getToggleButtonProps()}
        >
          {isOpen ? <>&#8593;</> : <>&#8595;</>}
        </button>
        <button
          style={{padding: '4px 8px'}}
          aria-label="clear selection"
          data-testid="clear-button"
          onClick={() => selectItem(null)}
        >
          &#10007;
        </button>
      </div>
      <ul {...getMenuProps()} className="menu">
        {isOpen
          ? inputItems.map((item, index) => (
              <li
                style={{
                  padding: '4px',
                  backgroundColor:
                    highlightedIndex === index ? '#bde4ff' : undefined,
                }}
                key={`${item}${index}`}
                {...getItemProps({
                  item,
                  index,
                  'data-testid': `downshift-item-${index}`,
                })}
              >
                {item}
              </li>
            ))
          : null}
      </ul>
    </div>
  )
}

import React from 'react';
import { useForm, ValidationMode } from 'react-hook-form';
import * as yup from 'yup';
import { yupResolver } from '@hookform/resolvers/yup';
import { useParams } from 'react-router-dom';

let renderCounter = 0;

const validationSchema = yup
  .object()
  .shape({
    firstName: yup.string().required(),
    lastName: yup.string().max(5).required(),
    select: yup.string().required(),
    radio: yup.string().required(),
    checkbox: yup.string().required(),
  })
  .required();

const FormStateWithSchema: React.FC = () => {
  const { mode } = useParams();
  const {
    register,
    handleSubmit,
    formState: {
      dirtyFields,
      isSubmitted,
      submitCount,
      touchedFields,
      isDirty,
      isSubmitting,
      isSubmitSuccessful,
      isValid,
    },
    reset,
  } = useForm<{
    firstName: string;
    lastName: string;
    select: string;
    radio: string | null;
    checkbox: boolean;
  }>({
    resolver: yupResolver(validationSchema),
    mode: mode as keyof ValidationMode,
    defaultValues: {
      firstName: '',
      lastName: '',
      select: '',
      checkbox: false,
      radio: null,
    },
  });
  const onSubmit = () => {};

  renderCounter++;

  return (
    <form onSubmit={handleSubmit(onSubmit)}>
      <input {...register('firstName')} placeholder="firstName" />
      <input {...register('lastName')} placeholder="lastName" />
      <select {...register('select')}>
        <option value="">Select</option>
        <option value={1}>1</option>
        <option value={2}>1</option>
      </select>
      Radio1
      <input type="radio" {...register('radio')} value="1" />
      Radio2
      <input type="radio" {...register('radio')} value="2" />
      Radio3
      <input type="radio" {...register('radio')} value="3" />
      <input type="checkbox" {...register('checkbox')} />
      <button id="submit">Submit</button>
      <button type="button" onClick={() => reset()} id="resetForm">
        Reset
      </button>
      <div id="state">
        {JSON.stringify({
          isSubmitted,
          submitCount,
          isDirty,
          isSubmitting,
          isSubmitSuccessful,
          isValid,
          touched: Object.keys(touchedFields),
          dirty: Object.keys(dirtyFields),
        })}
      </div>
      <div id="renderCount">{renderCounter}</div>
    </form>
  );
};

export default FormStateWithSchema;

import React from 'react';
import { useForm } from 'react-hook-form';

let renderCounter = 0;

const ConditionalField: React.FC = () => {
  const {
    register,
    handleSubmit,
    watch,
    formState: {
      dirtyFields,
      isSubmitted,
      submitCount,
      touchedFields,
      isDirty,
      isSubmitting,
      isSubmitSuccessful,
      isValid,
      errors,
    },
  } = useForm<{
    selectNumber: string;
    firstName: string;
    lastName: string;
    min: string;
    max: string;
    notRequired: string;
  }>({
    mode: 'onChange',
  });
  const [result, setResult] = React.useState({});

  const selectNumber = watch('selectNumber');

  renderCounter++;

  return (
    <form
      onSubmit={handleSubmit((data) => {
        setResult(data);
      })}
    >
      <select {...register('selectNumber', { required: true })}>
        <option value="">Select</option>
        <option value="1">1</option>
        <option value="2">2</option>
        <option value="3">3</option>
      </select>

      {selectNumber === '1' && (
        <>
          <input
            {...register('firstName', { required: true })}
            placeholder="firstName"
          />
          <input
            {...register('lastName', { required: true })}
            placeholder="lastName"
          />
        </>
      )}

      {selectNumber === '2' && (
        <>
          <input
            type="number"
            {...register('min', { required: true, min: 10 })}
            placeholder="min"
          />
          <input
            type="number"
            {...register('max', { required: true, max: 20 })}
            placeholder="max"
          />
        </>
      )}

      {selectNumber === '3' && (
        <>
          <input {...register('notRequired')} placeholder="notRequired" />
        </>
      )}

      <button id="submit">Submit</button>
      <div id="state">
        {JSON.stringify({
          isSubmitted,
          submitCount,
          isDirty,
          isSubmitting,
          isSubmitSuccessful,
          isValid,
          touched: Object.keys(touchedFields),
          dirty: Object.keys(dirtyFields),
        })}
      </div>
      <div id="result">{JSON.stringify(result)}</div>
      <div id="result">{typeof selectNumber}</div>
      <div id="renderCount">{renderCounter}</div>
    </form>
  );
};

export default ConditionalField;

import React, { useEffect } from 'react';
import { useForm } from 'react-hook-form';
import * as yup from 'yup';
import { yupResolver } from '@hookform/resolvers/yup';

let renderCounter = 0;

const validationSchema = yup
  .object()
  .shape({
    lastName: yup.string().min(10).required(),
    firstName: yup.string().min(10).required(),
    requiredField: yup.string().required(),
  })
  .required();

const SetValueWithSchema: React.FC = () => {
  const {
    register,
    setValue,
    handleSubmit,
    formState: { errors },
  } = useForm<{
    firstName: string;
    lastName: string;
    age: string;
    checkbox: boolean;
    radio: string;
    select: string;
    multiple: string[];
    requiredField: string;
  }>({
    resolver: yupResolver(validationSchema),
  });

  renderCounter++;

  useEffect(() => {
    register('firstName', { required: true });
    register('lastName', { required: true });
  }, [register]);

  return (
    <form
      onSubmit={handleSubmit((d) => {
        console.log(d);
      })}
    >
      <input
        name="firstName"
        placeholder="firstName"
        onChange={(e) => {
          setValue('firstName', e.target.value, {
            shouldValidate: true,
            shouldDirty: true,
          });
        }}
      />
      {errors.firstName && <p>firstName error</p>}

      <input
        name="lastName"
        placeholder="lastName"
        onChange={(e) => {
          setValue('lastName', e.target.value, {
            shouldValidate: true,
            shouldDirty: true,
          });
        }}
      />
      {errors.lastName && <p>lastName error</p>}

      <input
        {...register('age')}
        onChange={(e) => {
          setValue('age', e.target.value, {
            shouldValidate: true,
            shouldDirty: true,
          });
        }}
      />

      <input placeholder="requiredField" {...register('requiredField')} />
      {errors.requiredField && <p>RequiredField error</p>}

      <button
        type="button"
        id="setValue"
        onClick={() => {
          setValue('requiredField', 'test123456789', {
            shouldValidate: true,
            shouldDirty: true,
          });
        }}
      >
        firstName reset
      </button>

      <button id="submit">Submit</button>
      <div id="renderCount">{renderCounter}</div>
    </form>
  );
};

export default SetValueWithSchema;

import type { ReactNode } from 'react'
import type { ActiveHeadEntry, ResolvableHead as UseHeadInput } from 'unhead/types'
import React, { useCallback, useEffect, useMemo, useRef } from 'react'
import { HasElementTags, TagsWithInnerContent, ValidHeadTags } from 'unhead/utils'
import { useUnhead } from './composables'

interface HeadProps {
  children: ReactNode
  titleTemplate?: string
}

const Head: React.FC<HeadProps> = ({ children, titleTemplate }) => {
  const head = useUnhead()

  // Process children only when they change
  const processedElements = useMemo(() =>
    React.Children.toArray(children).filter(React.isValidElement), [children])

  const getHeadChanges = useCallback(() => {
    const input: UseHeadInput = {
      titleTemplate,
    }

    for (const element of processedElements) {
      const reactElement = element as React.ReactElement
      const { type, props } = reactElement
      const tagName = String(type)

      if (!ValidHeadTags.has(tagName)) {
        continue
      }

      const data: Record<string, any> = { ...(typeof props === 'object' ? props : {}) }

      if (TagsWithInnerContent.has(tagName) && data.children) {
        const contentKey = tagName === 'script' ? 'innerHTML' : 'textContent'
        data[contentKey] = Array.isArray(data.children)
          ? data.children.map(String).join('')
          : String(data.children)
      }
      delete data.children
      if (HasElementTags.has(tagName)) {
        const key = tagName as keyof UseHeadInput
        if (!Array.isArray(input[key])) {
          // @ts-expect-error untyped
          input[key] = []
        }
        (input[key] as any[])!.push(data)
      }
      else {
        // For singleton tags (title, base, etc.)
        // @ts-expect-error untyped
        input[tagName as keyof UseHeadInput] = data
      }
    }

    return input
  }, [processedElements, titleTemplate])

  const headRef = useRef<ActiveHeadEntry<any> | null>(
    head.push(getHeadChanges()),
  )

  useEffect(() => {
    return () => {
      if (headRef.current?.dispose) {
        headRef.current.dispose()
      }
      headRef.current = null
    }
  }, [])

  useEffect(() => {
    headRef.current?.patch(getHeadChanges())
  }, [getHeadChanges])

  return null
}

export { Head }

import { useCallback, useEffect, useRef, useState } from 'react';

export interface UseFetchOptions extends RequestInit {
  autoInvoke?: boolean;
}

export interface UseFetchReturnValue<T> {
  data: T | null;
  loading: boolean;
  error: Error | null;
  refetch: () => Promise<any>;
  abort: () => void;
}

export function useFetch<T>(
  url: string,
  { autoInvoke = true, ...options }: UseFetchOptions = {}
): UseFetchReturnValue<T> {
  const [data, setData] = useState<T | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<Error | null>(null);
  const controller = useRef<AbortController | null>(null);

  const refetch = useCallback(() => {
    if (controller.current) {
      controller.current.abort();
    }

    controller.current = new AbortController();

    setLoading(true);

    return fetch(url, { ...options, signal: controller.current.signal })
      .then((res) => {
        if (!res.ok) {
          throw new Error(`Request failed with status ${res.status}`);
        }
        return res.json();
      })
      .then((res) => {
        setData(res);
        setLoading(false);
        return res as T;
      })
      .catch((err) => {
        setLoading(false);

        if (err.name !== 'AbortError') {
          setError(err);
        }

        return err;
      });
  }, [url, JSON.stringify(options)]);

  const abort = useCallback(() => {
    if (controller.current) {
      controller.current?.abort('');
    }
  }, []);

  useEffect(() => {
    if (autoInvoke) {
      refetch();
    }

    return () => {
      if (controller.current) {
        controller.current.abort('');
      }
    };
  }, [refetch, autoInvoke]);

  return { data, loading, error, refetch, abort };
}

export namespace useFetch {
  export type Options = UseFetchOptions;
  export type ReturnValue<T> = UseFetchReturnValue<T>;
}

import React, { useEffect, useState } from 'react';
import { ErrorMessage, Field, Form, FormikProvider, useFormik } from 'formik';
import * as Yup from 'yup';
import { useRouter } from 'next/router';

const SignIn = () => {
  const router = useRouter();
  const [errorLog, setErrorLog] = useState([]);

  const formik = useFormik({
    validateOnMount: router.query.validateOnMount === 'true',
    validateOnBlur: router.query.validateOnBlur !== 'false',
    validateOnChange: router.query.validateOnChange !== 'false',
    initialValues: { username: '', password: '' },
    validationSchema: Yup.object().shape({
      username: Yup.string().required('Required'),
      password: Yup.string().required('Required'),
    }),
    onSubmit: async values => {
      await new Promise(r => setTimeout(r, 500));
      alert(JSON.stringify(values, null, 2));
    },
  });

  useEffect(() => {
    if (formik.errors.username && formik.touched.username) {
      setErrorLog(logs => [
        ...logs,
        {
          name: 'username',
          value: formik.values.username,
          error: formik.errors.username,
        },
      ]);
    }

    if (formik.errors.password && formik.touched.password) {
      setErrorLog(logs => [
        ...logs,
        {
          name: 'password',
          value: formik.values.password,
          error: formik.errors.password,
        },
      ]);
    }
  }, [
    formik.values.username,
    formik.errors.username,
    formik.touched.username,
    formik.values.password,
    formik.errors.password,
    formik.touched.password,
  ]);

  return (
    <div>
      <h1>Sign In</h1>

      <FormikProvider value={formik}>
        <Form>
          <div>
            <Field name="username" placeholder="Username" />
            <ErrorMessage name="username" component="p" />
          </div>

          <div>
            <Field name="password" placeholder="Password" type="password" />
            <ErrorMessage name="password" component="p" />
          </div>

          <button type="submit" disabled={!formik.isValid}>
            Submit
          </button>

          <button
            type="reset"
            onClick={() => {
              setErrorLog([]);
            }}
          >
            Reset
          </button>

          <pre id="error-log">{JSON.stringify(errorLog, null, 2)}</pre>
        </Form>
      </FormikProvider>
    </div>
  );
};

export default SignIn;

import { ScrollArea, SimpleGrid } from '@mantine/core';
import { useTimePickerContext } from '../TimePicker.context';
import {
  TimePickerAmPmLabels,
  TimePickerFormat,
  TimePickerPresetGroup,
  TimePickerPresets,
} from '../TimePicker.types';
import { isSameTime } from '../utils/is-same-time/is-same-time';
import { TimePresetControl } from './TimePresetControl';
import { TimePresetGroup } from './TimePresetGroup';

interface TimePresetsProps {
  presets: TimePickerPresets;
  format: TimePickerFormat;
  amPmLabels: TimePickerAmPmLabels;
  value: string;
  withSeconds: boolean;
  onChange: (value: string) => void;
}

export function TimePresets({
  presets,
  format,
  amPmLabels,
  withSeconds,
  value,
  onChange,
}: TimePresetsProps) {
  const ctx = useTimePickerContext();

  if (presets.length === 0) {
    return null;
  }

  if (typeof presets[0] === 'string') {
    const items = (presets as string[]).map((item) => (
      <TimePresetControl
        key={item}
        value={item}
        format={format}
        amPmLabels={amPmLabels}
        withSeconds={withSeconds}
        active={isSameTime({ time: item, compare: value, withSeconds })}
        onChange={onChange}
      />
    ));

    return (
      <ScrollArea.Autosize
        mah={ctx.maxDropdownContentHeight}
        type="never"
        {...ctx.getStyles('scrollarea')}
        {...ctx.scrollAreaProps}
      >
        <div {...ctx.getStyles('presetsRoot')}>
          <SimpleGrid cols={withSeconds ? 2 : 3} spacing={4}>
            {items}
          </SimpleGrid>
        </div>
      </ScrollArea.Autosize>
    );
  }

  const groups = (presets as TimePickerPresetGroup[]).map((group, index) => (
    <TimePresetGroup
      key={index}
      data={group}
      value={value}
      format={format}
      amPmLabels={amPmLabels}
      withSeconds={withSeconds}
      onChange={onChange}
    />
  ));

  return (
    <ScrollArea.Autosize
      mah={ctx.maxDropdownContentHeight}
      type="never"
      {...ctx.getStyles('scrollarea')}
      {...ctx.scrollAreaProps}
    >
      <div {...ctx.getStyles('presetsRoot')}>{groups}</div>
    </ScrollArea.Autosize>
  );
}

TimePresets.displayName = '@mantine/dates/TimePresets';

import { useCallback, useEffect, useState } from 'react';

export interface UseMouseReturnValue<T extends HTMLElement = any> {
  ref: React.RefCallback<T | null>;
  x: number;
  y: number;
}

export function useMouse<T extends HTMLElement = any>(
  options: { resetOnExit?: boolean } = { resetOnExit: false }
): UseMouseReturnValue<T> {
  const [position, setPosition] = useState({ x: 0, y: 0 });

  const refCallback: React.RefCallback<T | null> = useCallback(
    (node) => {
      const setMousePosition = (event: Event) => {
        const mouseEvent = event as globalThis.MouseEvent;
        if (node) {
          const rect = node.getBoundingClientRect();

          const x = Math.max(0, Math.round(mouseEvent.clientX - rect.left));

          const y = Math.max(0, Math.round(mouseEvent.clientY - rect.top));

          setPosition({ x, y });
        } else {
          setPosition({ x: mouseEvent.clientX, y: mouseEvent.clientY });
        }
      };

      const resetMousePosition = () => setPosition({ x: 0, y: 0 });

      node?.addEventListener('mousemove', setMousePosition);
      if (options.resetOnExit) {
        node?.addEventListener('mouseleave', resetMousePosition);
      }

      return () => {
        node?.removeEventListener('mousemove', setMousePosition);
        if (options.resetOnExit) {
          node?.removeEventListener('mouseleave', resetMousePosition);
        }
      };
    },
    [options.resetOnExit]
  );

  return { ref: refCallback, ...position };
}

export interface UseMousePositionReturnValue {
  x: number;
  y: number;
}

export function useMousePosition(): UseMousePositionReturnValue {
  const [position, setPosition] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const setMousePosition = (event: MouseEvent) => {
      setPosition({ x: event.clientX, y: event.clientY });
    };

    document.addEventListener('mousemove', setMousePosition);

    return () => {
      document.removeEventListener('mousemove', setMousePosition);
    };
  }, []);

  return position;
}

export namespace useMouse {
  export type ReturnValue<T extends HTMLElement> = UseMouseReturnValue<T>;
}

export namespace useMousePosition {
  export type ReturnValue = UseMousePositionReturnValue;
}

import { use, useRef } from 'react';
import { useMergedRef } from '@mantine/hooks';
import {
  BoxProps,
  CompoundStylesApiProps,
  createEventHandler,
  ElementProps,
  factory,
  Factory,
  useProps,
} from '../../../core';
import { Popover } from '../../Popover';
import { useMenuContext } from '../Menu.context';
import { SubMenuContext } from '../MenuSub/MenuSub.context';
import { useMenuTypeAhead } from '../use-menu-type-ahead';
import classes from '../Menu.module.css';

export type MenuSubDropdownStylesNames = 'dropdown';

export interface MenuSubDropdownProps
  extends BoxProps, CompoundStylesApiProps<MenuSubDropdownFactory>, ElementProps<'div'> {}

export type MenuSubDropdownFactory = Factory<{
  props: MenuSubDropdownProps;
  ref: HTMLDivElement;
  stylesNames: MenuSubDropdownStylesNames;
  compound: true;
}>;

export const MenuSubDropdown = factory<MenuSubDropdownFactory>((props) => {
  const {
    classNames,
    className,
    style,
    styles,
    vars,
    onMouseEnter,
    onMouseLeave,
    onPointerEnter,
    onPointerLeave,
    onKeyDown,
    children,
    ref,
    ...others
  } = useProps('MenuSubDropdown', null, props);

  const wrapperRef = useRef<HTMLDivElement>(null);
  const ctx = useMenuContext();
  const subCtx = use(SubMenuContext);

  const typeAhead = useMenuTypeAhead({
    enabled: !ctx.hasSearch,
    opened: subCtx?.opened ?? false,
    getDropdown: () => wrapperRef.current,
  });

  const handleKeyDown = createEventHandler<any>(onKeyDown, (event) => {
    typeAhead(event);
    if (
      !event.ctrlKey &&
      !event.metaKey &&
      !event.altKey &&
      event.key.length === 1 &&
      event.key !== ' '
    ) {
      event.stopPropagation();
    }
  });

  const floatingProps = subCtx?.getFloatingProps({
    onMouseEnter,
    onMouseLeave,
    onPointerEnter,
    onPointerLeave,
  });

  return (
    <Popover.Dropdown
      {...others}
      {...floatingProps}
      role="menu"
      aria-orientation="vertical"
      ref={useMergedRef(ref, wrapperRef, subCtx?.setFloating)}
      {...ctx.getStyles('dropdown', {
        className,
        style,
        styles,
        classNames,
        withStaticClass: false,
      })}
      tabIndex={-1}
      data-menu-dropdown
      onKeyDown={handleKeyDown}
    >
      {children}
    </Popover.Dropdown>
  );
});

MenuSubDropdown.classes = classes;
MenuSubDropdown.displayName = '@mantine/core/MenuSubDropdown';

import { getColumns, HeatmapColumn } from './get-columns/get-columns';
import { getHeatColor } from './get-heat-color/get-heat-color';
import { HeatmapWeeksSharedProps } from './HeatmapWeeks.types';

export function HeatmapSplitWeeks({
  data,
  datesRange,
  rectSize,
  gap,
  rectRadius,
  min,
  max,
  colors,
  withTooltip,
  setHoveredRect,
  getRectProps,
  getStyles,
}: HeatmapWeeksSharedProps) {
  const rectSizeWithGap = rectSize + gap;

  // Columns: computed by a helper so logic is isolated
  const columns: HeatmapColumn[] = getColumns(datesRange, true);

  return (
    <>
      {columns.map((col, columnIndex) => {
        if (col.type === 'spacer') {
          return (
            <g
              key={`spacer-${columnIndex}`}
              transform={`translate(${columnIndex * rectSizeWithGap}, 0)`}
            />
          );
        }

        const week = datesRange[col.weekIndex];

        const days = week.map((date, dayIndex) => {
          if (!date) {
            return null;
          }
          if (new Date(date).getUTCMonth() !== col.month) {
            return null;
          }

          const hasValue = date in data && data[date] !== null;
          const rectValue = hasValue ? data[date] : null;

          return (
            <rect
              key={`${date}-${col.month}`}
              width={rectSize}
              height={rectSize}
              x={gap}
              y={dayIndex * rectSizeWithGap + gap}
              rx={rectRadius}
              data-empty={!hasValue || undefined}
              fill={hasValue ? getHeatColor({ value: data[date], min, max, colors }) : undefined}
              onPointerEnter={
                withTooltip ? () => setHoveredRect({ date, value: rectValue }) : undefined
              }
              {...getRectProps?.({ date, value: rectValue })}
              {...getStyles('rect')}
            />
          );
        });

        return (
          <g
            key={`col-${col.weekIndex}-${col.month}-${columnIndex}`}
            transform={`translate(${columnIndex * rectSizeWithGap}, 0)`}
            data-id="week"
          >
            {days}
          </g>
        );
      })}
    </>
  );
}

import { useCallback, useEffect, useRef } from 'react';
import { scopeTab } from './scope-tab';
import { FOCUS_SELECTOR, focusable, tabbable } from './tabbable';

export function useFocusTrap(active = true): React.RefCallback<HTMLElement | null> {
  const ref = useRef<HTMLElement>(null);

  const focusNode = (node: HTMLElement) => {
    let focusElement: HTMLElement | null = node.querySelector('[data-autofocus]');

    if (!focusElement) {
      const children = Array.from<HTMLElement>(node.querySelectorAll(FOCUS_SELECTOR));
      focusElement = children.find(tabbable) || children.find(focusable) || null;
      if (!focusElement && focusable(node)) {
        focusElement = node;
      }
    }

    if (focusElement) {
      focusElement.focus({ preventScroll: true });
    } else if (process.env.NODE_ENV === 'development') {
      // oxlint-disable-next-line no-console
      console.warn(
        '[@mantine/hooks/use-focus-trap] Failed to find focusable element within provided node',
        node
      );
    }
  };

  const setRef = useCallback(
    (node: HTMLElement | null) => {
      if (!active) {
        return;
      }

      if (node === null) {
        ref.current = null;
        return;
      }

      if (ref.current === node) {
        return;
      }

      // Delay processing the HTML node by a frame. This ensures focus is assigned correctly.
      setTimeout(() => {
        if (node.getRootNode()) {
          focusNode(node);
        } else if (process.env.NODE_ENV === 'development') {
          // oxlint-disable-next-line no-console
          console.warn('[@mantine/hooks/use-focus-trap] Ref node is not part of the dom', node);
        }
      });

      ref.current = node;
    },
    [active]
  );

  useEffect(() => {
    if (!active) {
      return undefined;
    }

    if (ref.current) {
      setTimeout(() => {
        if (ref.current) {
          focusNode(ref.current);
        }
      });
    }

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === 'Tab' && ref.current) {
        scopeTab(ref.current, event);
      }
    };

    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [active]);

  return setRef;
}

