export interface PanelBodyProps
  extends WithAsProps,
    AnimationEventProps,
    React.HTMLAttributes<HTMLDivElement> {
  collapsible?: boolean;
  expanded?: boolean;
  bodyFill?: boolean;
  scrollShadow?: boolean;
  role?: string;
  id?: string;
  labelId?: string;
}

const PanelBody = (props: PanelBodyProps) => {
  const {
    classPrefix = 'panel-body',
    children,
    collapsible,
    expanded,
    bodyFill,
    role,
    id,
    labelId,
    scrollShadow,
    className,
    onEnter,
    onEntering,
    onEntered,
    onExit,
    onExiting,
    onExited,
    onScroll,
    ...rest
  } = props;

  const { merge, prefix, withPrefix } = useStyles(classPrefix);
  const bodyClasses = merge(className, withPrefix({ fill: bodyFill }));

  const renderBody = (bodyProps?: React.HTMLAttributes<HTMLDivElement>) => {
    return (
      <ScrollView
        {...rest}
        {...bodyProps}
        customScrollbar
        className={bodyClasses}
        onScroll={onScroll}
        scrollShadow={scrollShadow}
      >
        {children}
      </ScrollView>
    );
  };

  return collapsible ? (
    <Collapse
      in={expanded}
