import { type Dict, isObject, memo, walkObject } from "../utils"
import type { SystemContext } from "./types"

export function createSerializeFn(
  options: Pick<SystemContext, "conditions" | "isValidProperty">,
) {
  const { conditions, isValidProperty } = options

  const isSelectorLike = memo((prop: string, valueKeys: string): boolean => {
    if (!isValidProperty(prop)) return true
    return !valueKeys
      .split(",")
      .every((key) => key === "base" || conditions.has(key))
  })

  return function serialize(styles: Dict) {
    return walkObject(styles, (value) => value, {
      stop: (value) => Array.isArray(value),
      getKey: (prop, value) => {
        if (!isObject(value)) return prop

        if (conditions.has(prop)) return prop

        if (isSelectorLike(prop, Object.keys(value).join(","))) {
          return parseSelectors(prop)
            .map((s) => {
              const selector = s.startsWith("&") ? s.slice(1) : s
              return isTopLevelSelector(selector)
                ? `${selector} &`
                : `&${selector}`
            })
            .join(", ")
        }

        return prop
      },
    })
  }
}

function isTopLevelSelector(s: string): boolean {
  const lower = s.toLowerCase()
  return (
    lower.startsWith(":host-context") ||
    lower.startsWith(":host") ||
    lower.startsWith("::slotted")
  )
}

function parseSelectors(selector: string): string[] {
  const result = [] as string[]
  let parenCount = 0
  let currentSelector = ""
  let inEscape = false

  for (let i = 0; i < selector.length; i++) {
    const char = selector[i]

    if (char === "\\" && !inEscape) {
      inEscape = true
      currentSelector += char
      continue
    }

    if (inEscape) {
      inEscape = false
      currentSelector += char
      continue
    }

    if (char === "(") {
      parenCount++
    } else if (char === ")") {
      parenCount--
    }

    if (char === "," && parenCount === 0) {
      result.push(currentSelector.trim())
      currentSelector = ""
    } else {
      currentSelector += char
    }
  }

  if (currentSelector) {
    result.push(currentSelector.trim())
  }

  return result
}

import type { API, FileInfo, Options } from "jscodeshift"
import { createParserFromPath } from "../../utils/parser"

export default function transformer(
  file: FileInfo,
  _api: API,
  _options: Options,
) {
  const j = createParserFromPath(file.path)
  const root = j(file.source)

  const chakraLinkNames: string[] = []

  root
    .find(j.ImportDeclaration, { source: { value: "@chakra-ui/react" } })
    .forEach((path) => {
      path.node.specifiers?.forEach((spec) => {
        if (
          spec.type === "ImportSpecifier" &&
          (spec.imported.name === "Link" ||
            spec.imported.name === "LinkOverlay") &&
          spec.local?.name
        ) {
          chakraLinkNames.push(spec.local.name as string)
        }
      })
    })

  if (chakraLinkNames.length === 0) {
    return root.toSource({ quote: "single" })
  }

  root
    .find(j.JSXElement, {
      openingElement: (el) =>
        el.name.type === "JSXIdentifier" &&
        chakraLinkNames.includes(el.name.name),
    })
    .forEach((path) => {
      const attrs = path.node.openingElement.attributes
      if (!attrs) return

      const attrsToRemove: number[] = []
      let hasIsExternal = false

      attrs.forEach((attr, index) => {
        if (attr.type !== "JSXAttribute") return
        if (attr.name.name === "isExternal") {
          hasIsExternal = true
          attrsToRemove.push(index)
        }
      })

      attrsToRemove.reverse().forEach((index) => {
        attrs.splice(index, 1)
      })

      if (hasIsExternal) {
        const hasTarget = attrs.some(
          (attr) => attr.type === "JSXAttribute" && attr.name.name === "target",
        )

        if (!hasTarget) {
          attrs.push(
            j.jsxAttribute(
              j.jsxIdentifier("target"),
              j.stringLiteral("_blank"),
            ),
          )
        }

        const hasRel = attrs.some(
          (attr) => attr.type === "JSXAttribute" && attr.name.name === "rel",
        )

        if (!hasRel) {
          attrs.push(
            j.jsxAttribute(
              j.jsxIdentifier("rel"),
              j.stringLiteral("noopener noreferrer"),
            ),
          )
        }
      }
    })

  return root.toSource({ quote: "single" })
}

import type { API, FileInfo, Options } from "jscodeshift"
import { createParserFromPath } from "../../utils/parser"

const CHAKRA_SOURCES = ["@chakra-ui/react", "@/components/ui"]

export default function transform(
  file: FileInfo,
  _api: API,
  _options: Options,
) {
  const j = createParserFromPath(file.path)
  const root = j(file.source)

  const chakraLocalNames = new Set<string>()
  root.find(j.ImportDeclaration).forEach((path) => {
    const source = path.node.source.value
    if (
      typeof source === "string" &&
      CHAKRA_SOURCES.some((s) => source.includes(s))
    ) {
      path.node.specifiers?.forEach((spec) => {
        if (spec.local) chakraLocalNames.add(spec.local.name as string)
      })
    }
  })

  if (chakraLocalNames.size === 0) return file.source

  const renameObjectProps = (objectNode: any) => {
    if (objectNode.type !== "ObjectExpression") return

    objectNode.properties.forEach((prop: any) => {
      if (prop.type === "Property" && !prop.computed) {
        const keyName =
          prop.key.type === "Identifier" ? prop.key.name : prop.key.value

        if (keyName === "spacing") {
          if (prop.key.type === "Identifier") {
            prop.key.name = "gap"
          } else {
            prop.key.value = "gap"
          }
        }
      }
    })
  }

  root.find(j.JSXOpeningElement).forEach((path) => {
    const nameNode = path.node.name
    let baseName = ""

    if (nameNode.type === "JSXIdentifier") {
      baseName = nameNode.name
    } else if (nameNode.type === "JSXMemberExpression") {
      let current: any = nameNode
      while (current.object) current = current.object
      baseName = current.name
    }

    if (!chakraLocalNames.has(baseName)) return

    j(path)
      .find(j.JSXAttribute)
      .forEach((attrPath) => {
        const name = attrPath.node.name
        if (name.type !== "JSXIdentifier") return

        if (name.name === "spacing") {
          name.name = "gap"
        }
      })

    j(path)
      .find(j.JSXSpreadAttribute)
      .forEach((spreadPath) => {
        const arg = spreadPath.node.argument
        if (arg.type === "ObjectExpression") {
          renameObjectProps(arg)
        }
      })
  })

  return root.toSource({ quote: "single" })
}

import type { API, FileInfo, Options } from "jscodeshift"
import { collectChakraLocalNames } from "../../utils/chakra-tracker"
import { createParserFromPath } from "../../utils/parser"

export default function transform(
  file: FileInfo,
  _api: API,
  _options: Options,
) {
  const j = createParserFromPath(file.path)
  const root = j(file.source)

  const { chakraLocalNames } = collectChakraLocalNames(j, root)

  if (chakraLocalNames.size === 0) {
    return file.source
  }

  let hasChakraSystemPropsImport = false

  root.find(j.ImportDeclaration).forEach((path) => {
    if (path.node.source.value !== "@chakra-ui/react") return

    path.node.specifiers?.forEach((spec) => {
      if (
        spec.type === "ImportSpecifier" &&
        spec.imported.name === "SystemProps"
      ) {
        hasChakraSystemPropsImport = true
      }
    })
  })

  if (!hasChakraSystemPropsImport) {
    return file.source
  }

  root.find(j.Identifier, { name: "SystemProps" }).forEach((path) => {
    const parent = path.parent.node

    // Only touch type positions
    if (
      parent.type.startsWith("TS") ||
      parent.type === "TSTypeReference" ||
      parent.type === "TSIndexedAccessType"
    ) {
      path.node.name = "SystemStyleObject"
    }
  })

  root.find(j.ImportDeclaration).forEach((path) => {
    if (path.node.source.value !== "@chakra-ui/react") return

    let systemPropsSpec: any = null
    let hasSystemStyleObject = false

    path.node.specifiers?.forEach((spec) => {
      if (spec.type !== "ImportSpecifier") return

      if (spec.imported.name === "SystemProps") {
        systemPropsSpec = spec
      }

      if (spec.imported.name === "SystemStyleObject") {
        hasSystemStyleObject = true
      }
    })

    if (!systemPropsSpec) return

    // Remove SystemProps
    path.node.specifiers = path.node.specifiers!.filter(
      (spec) => spec !== systemPropsSpec,
    )

    // Add SystemStyleObject if missing
    if (!hasSystemStyleObject) {
      path.node.specifiers!.push(
        j.importSpecifier(j.identifier("SystemStyleObject")),
      )
    }
  })

  return root.toSource({ quote: "single" })
}

import { ColorFormat, HsvaColor, RgbaColor } from '../ColorPicker.types';
import { round } from './parsers';

export function hsvaToRgbaObject({ h, s, v, a }: HsvaColor): RgbaColor {
  const _h = (h / 360) * 6;
  const _s = s / 100;
  const _v = v / 100;

  const hh = Math.floor(_h);
  const l = _v * (1 - _s);
  const c = _v * (1 - (_h - hh) * _s);
  const d = _v * (1 - (1 - _h + hh) * _s);
  const module = hh % 6;

  return {
    r: round([_v, c, l, l, d, _v][module] * 255),
    g: round([d, _v, _v, c, l, l][module] * 255),
    b: round([l, l, d, _v, _v, c][module] * 255),
    a: round(a, 2),
  };
}

export function hsvaToRgba(color: HsvaColor, includeAlpha: boolean) {
  const { r, g, b, a } = hsvaToRgbaObject(color);

  if (!includeAlpha) {
    return `rgb(${r}, ${g}, ${b})`;
  }

  return `rgba(${r}, ${g}, ${b}, ${round(a, 2)})`;
}

export function hsvaToHsl({ h, s, v, a }: HsvaColor, includeAlpha: boolean) {
  const hh = ((200 - s) * v) / 100;

  const result = {
    h: Math.round(h),
    s: Math.round(hh > 0 && hh < 200 ? ((s * v) / 100 / (hh <= 100 ? hh : 200 - hh)) * 100 : 0),
    l: Math.round(hh / 2),
  };

  if (!includeAlpha) {
    return `hsl(${result.h}, ${result.s}%, ${result.l}%)`;
  }

  return `hsla(${result.h}, ${result.s}%, ${result.l}%, ${round(a, 2)})`;
}

function formatHexPart(number: number) {
  const hex = number.toString(16);
  return hex.length < 2 ? `0${hex}` : hex;
}

export function hsvaToHex(color: HsvaColor) {
  const { r, g, b } = hsvaToRgbaObject(color);
  return `#${formatHexPart(r)}${formatHexPart(g)}${formatHexPart(b)}`;
}

export function hsvaToHexa(color: HsvaColor) {
  const a = Math.round(color.a * 255);

  return `${hsvaToHex(color)}${formatHexPart(a)}`;
}

const CONVERTERS: Record<ColorFormat, (color: HsvaColor) => string> = {
  hex: hsvaToHex,
  hexa: (color) => hsvaToHexa(color),
  rgb: (color) => hsvaToRgba(color, false),
  rgba: (color) => hsvaToRgba(color, true),
  hsl: (color) => hsvaToHsl(color, false),
  hsla: (color) => hsvaToHsl(color, true),
};

export function convertHsvaTo(format: ColorFormat, color: HsvaColor) {
  if (!color) {
    return '#000000';
  }

  if (!(format in CONVERTERS)) {
    return CONVERTERS.hex(color);
  }

  return CONVERTERS[format](color);
}

'use client';
import { createBreakpoints, createSpacing } from '@mui/system';

export default function adaptV4Theme(inputTheme) {
  if (process.env.NODE_ENV !== 'production') {
    console.warn(
      [
        'MUI: adaptV4Theme() is deprecated.',
        'Follow the upgrade guide on https://mui.com/r/migration-v4#theme.',
      ].join('\n'),
    );
  }

  const {
    defaultProps = {},
    mixins = {},
    overrides = {},
    palette = {},
    props = {},
    styleOverrides = {},
    ...other
  } = inputTheme;
  const theme = {
    ...other,
    components: {},
  };

  // default props
  Object.keys(defaultProps).forEach((component) => {
    const componentValue = theme.components[component] || {};
    componentValue.defaultProps = defaultProps[component];
    theme.components[component] = componentValue;
  });

  Object.keys(props).forEach((component) => {
    const componentValue = theme.components[component] || {};
    componentValue.defaultProps = props[component];
    theme.components[component] = componentValue;
  });

  // CSS overrides
  Object.keys(styleOverrides).forEach((component) => {
    const componentValue = theme.components[component] || {};
    componentValue.styleOverrides = styleOverrides[component];
    theme.components[component] = componentValue;
  });

  Object.keys(overrides).forEach((component) => {
    const componentValue = theme.components[component] || {};
    componentValue.styleOverrides = overrides[component];
    theme.components[component] = componentValue;
  });

  // theme.spacing
  theme.spacing = createSpacing(inputTheme.spacing);

  // theme.mixins.gutters
  const breakpoints = createBreakpoints(inputTheme.breakpoints || {});
  const spacing = theme.spacing;

  theme.mixins = {
    gutters: (styles = {}) => {
      return {
        paddingLeft: spacing(2),
        paddingRight: spacing(2),
        ...styles,
        [breakpoints.up('sm')]: {
          paddingLeft: spacing(3),
          paddingRight: spacing(3),
          ...styles[breakpoints.up('sm')],
        },
      };
    },
    ...mixins,
  };

  const { type: typeInput, mode: modeInput, ...paletteRest } = palette;

  const finalMode = modeInput || typeInput || 'light';

  theme.palette = {
    // theme.palette.text.hint
    text: {
      hint: finalMode === 'dark' ? 'rgba(255, 255, 255, 0.5)' : 'rgba(0, 0, 0, 0.38)',
    },
    mode: finalMode,
    type: finalMode,
    ...paletteRest,
  };

  return theme;
}

import { type CartesianExtremumGetter } from '../../internals/plugins/corePlugins/useChartSeriesConfig';

export const getExtremumX: CartesianExtremumGetter<'scatter'> = (params) => {
  const { series, axis, isDefaultAxis, getFilters } = params;

  let min = Infinity;
  let max = -Infinity;

  for (const seriesId in series) {
    if (!Object.hasOwn(series, seriesId)) {
      continue;
    }

    if (axis.domainSeries === 'visible' && series[seriesId].hidden) {
      continue;
    }

    const axisId = series[seriesId].xAxisId;
    if (!(axisId === axis.id || (axisId === undefined && isDefaultAxis))) {
      continue;
    }

    const filter = getFilters?.({
      currentAxisId: axis.id,
      isDefaultAxis,
      seriesXAxisId: series[seriesId].xAxisId,
      seriesYAxisId: series[seriesId].yAxisId,
    });

    const seriesData = series[seriesId].data ?? [];

    for (let i = 0; i < seriesData.length; i += 1) {
      const d = seriesData[i];

      if (filter && !filter(d, i)) {
        continue;
      }

      if (d.x !== null) {
        if (d.x < min) {
          min = d.x;
        }
        if (d.x > max) {
          max = d.x;
        }
      }
    }
  }

  return [min, max];
};

export const getExtremumY: CartesianExtremumGetter<'scatter'> = (params) => {
  const { series, axis, isDefaultAxis, getFilters } = params;

  let min = Infinity;
  let max = -Infinity;

  for (const seriesId in series) {
    if (!Object.hasOwn(series, seriesId)) {
      continue;
    }

    if (axis.domainSeries === 'visible' && series[seriesId].hidden) {
      continue;
    }

    const axisId = series[seriesId].yAxisId;
    if (!(axisId === axis.id || (axisId === undefined && isDefaultAxis))) {
